)

type APIStatus interface {
	StatusCode() int
	Message() string
}

type StatusResponse struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

func ErrorToStatusCode(err error) int {
	switch e := err.(type) {
	case *NotFoundError:
		return http.StatusNotFound
	case *ValidationAPIError:
		return http.StatusBadRequest
	case *UpstreamError:
		return http.StatusBadGateway
	case *InternalError:
		return http.StatusInternalServerError
	default:
		return http.StatusInternalServerError
	}
}

func ErrorToResponse(err error) StatusResponse {
	switch e := err.(type) {
	case *NotFoundError:
		return StatusResponse{Code: 404, Message: e.Error()}
	case *ValidationAPIError:
		return StatusResponse{Code: 400, Message: e.Error()}
	case *UpstreamError:
		return StatusResponse{Code: 502, Message: e.Error()}
	case *InternalError:
		return StatusResponse{Code: 500, Message: e.Error()}
	default:
		return StatusResponse{Code: 500, Message: fmt.Sprintf("unknown error: %v", err)}
	}
}

package store

import (
	"os"
	"sync"
)

var (
	storeInstance Store
	storeOnce     sync.Once
)

func Storage() Store {
	storeOnce.Do(func() {
		storeType := os.Getenv("STORE_TYPE")
		if storeType == "" {
			storeType = "redis"
		}
		storeInstance = initStore(storeType)
	})
	return storeInstance
}

func initStore(storeType string) Store {
	switch storeType {
	case "redis":
		addr := os.Getenv("REDIS_ADDR")
		password := os.Getenv("REDIS_PASSWORD")
		required := os.Getenv("REDIS_PASSWORD_REQUIRED")
		if password == "" && required != "false" {
			return nil
		}
		return newRedisStore(addr, password)
	case "valkey":
		addr := os.Getenv("VALKEY_ADDR")
		password := os.Getenv("VALKEY_PASSWORD")
		required := os.Getenv("VALKEY_PASSWORD_REQUIRED")
		if password == "" && required != "false" {
			return nil
		}
		return newValkeyStore(addr, password)
	default:
		return newRedisStore(os.Getenv("REDIS_ADDR"), os.Getenv("REDIS_PASSWORD"))
	}
}

