type redisStore struct {
	client *redis.Client
}

func newRedisStore(addr, password string) Store {
	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})
	return &redisStore{client: client}
}

func (s *redisStore) Ping() error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	result, err := s.client.Ping(ctx).Result()
	if err != nil {
		return err
	}
	if result != "PONG" {
		return fmt.Errorf("unexpected ping response: %s", result)
	}
	return nil
}

func (s *redisStore) makeRedisOptions() *redis.Options {
	return s.client.Options()
}

func (s *redisStore) GetSandboxBySessionID(sessionID string) (*SandboxInfo, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := fmt.Sprintf("session:%s", sessionID)
	data, err := s.client.Get(ctx, key).Bytes()
	if err != nil {
		if err == redis.Nil {
			return nil, ErrNotFound
		}
		return nil, err
	}
	var info SandboxInfo
	if err := json.Unmarshal(data, &info); err != nil {
		return nil, err
	}
	return &info, nil
}

func (s *redisStore) StoreSandbox(sessionID string, info *SandboxInfo) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := fmt.Sprintf("session:%s", sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}
	pipe := s.client.Pipeline()
	pipe.SetNX(ctx, key, data, 0)
	if info.ExpiresAt > 0 {
		pipe.ZAdd(ctx, "session:expiry", redis.Z{
			Score:  float64(info.ExpiresAt),
			Member: sessionID,
		})
	}
	if info.LastActivity > 0 {
		pipe.ZAdd(ctx, "session:last_activity", redis.Z{
			Score:  float64(info.LastActivity),
			Member: sessionID,
		})
	}
	_, err = pipe.Exec(ctx)
	return err
}

func (s *redisStore) UpdateSandbox(sessionID string, info *SandboxInfo) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := fmt.Sprintf("session:%s", sessionID)
	data, err := json.Marshal(info)
	if err != nil {
		return err
	}
	return s.client.Set(ctx, key, data, 0).Err()
}

func (s *redisStore) DeleteSandboxBySessionID(sessionID string) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := fmt.Sprintf("session:%s", sessionID)
	pipe := s.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, "session:expiry", sessionID)
	pipe.ZRem(ctx, "session:last_activity", sessionID)
	_, err := pipe.Exec(ctx)
	return err
}

func (s *redisStore) ListExpiredSandboxes(before int64, limit int) ([]*SandboxInfo, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	cutoff := strconv.FormatInt(before, 10)
	ids, err := s.client.ZRangeByScore(ctx, "session:expiry", &redis.ZRangeBy{
		Min:   "-inf",
		Max:   cutoff,
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}
	return s.getSandboxesByIDs(ctx, ids)
}

func (s *redisStore) ListInactiveSandboxes(before int64, limit int) ([]*SandboxInfo, error) {
	ctx, cancel := context.WithTimeout(context.Background(), 10*time.Second)
	defer cancel()
	cutoff := strconv.FormatInt(before, 10)
	ids, err := s.client.ZRangeByScore(ctx, "session:last_activity", &redis.ZRangeBy{
		Min:   "-inf",
		Max:   cutoff,
		Count: int64(limit),
	}).Result()
	if err != nil {
		return nil, err
	}
	return s.getSandboxesByIDs(ctx, ids)
}

func (s *redisStore) getSandboxesByIDs(ctx context.Context, ids []string) ([]*SandboxInfo, error) {
	if len(ids) == 0 {
		return []*SandboxInfo{}, nil
	}
	pipe := s.client.Pipeline()
	cmds := make([]*redis.StringCmd, len(ids))
	for i, id := range ids {
		cmds[i] = pipe.Get(ctx, fmt.Sprintf("session:%s", id))
	}
	_, err := pipe.Exec(ctx)
	if err != nil && err != redis.Nil {
		return nil, err
	}
	var result []*SandboxInfo
	for _, cmd := range cmds {
		data, err := cmd.Bytes()
		if err != nil {
			continue
		}
		var info SandboxInfo
		if err := json.Unmarshal(data, &info); err != nil {
			continue
		}
		result = append(result, &info)
	}
	return result, nil
}

func (s *redisStore) UpdateSessionLastActivity(sessionID string, timestamp int64) error {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()
	key := fmt.Sprintf("session:%s", sessionID)
	exists, err := s.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}
	return s.client.ZAdd(ctx, "session:last_activity", redis.Z{
		Score:  float64(timestamp),
		Member: sessionID,
	}).Err()
}

func (s *redisStore) Close() error {
	return s.client.Close()
}
